import base64
import zlib
import requests
from urllib.parse import quote_plus
from datetime import datetime
from uuid import uuid4

def build_saml_request(destination_url, user_info):
    saml_request_template = '''<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" 
                            AssertionConsumerServiceURL="{acs_url}" 
                            Destination="{destination}" 
                            ID="{request_id}" 
                            IssueInstant="{issue_instant}" 
                            Version="2.0">
        <saml:Issuer xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion">{issuer}</saml:Issuer>
    </samlp:AuthnRequest>'''

    request_id = '_' + uuid4().hex
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

    saml_request = saml_request_template.format(
        acs_url=user_info['acs_url'],
        destination=destination_url,
        request_id=request_id,
        issue_instant=issue_instant,
        issuer=user_info['issuer']
    )

    def encode_saml_request(saml_request):
        compressed_request = zlib.compress(saml_request.encode('utf-8'))
        base64_encoded_request = base64.b64encode(compressed_request)
        return quote_plus(base64_encoded_request)

    encoded_request = encode_saml_request(saml_request)
    post_to_idp(destination_url, encoded_request)

def post_to_idp(destination_url, encoded_request):
    headers = {'Content-Type': 'application/x-www-form-urlencoded'}
    payload = {'SAMLRequest': encoded_request}
    response = requests.post(destination_url, data=payload, headers=headers)
    return response

